const c=$json,tz=c.timezone||'America/Sao_Paulo';
const d=x=>Object.fromEntries(new Intl.DateTimeFormat('en-CA',{timeZone:tz,year:'numeric',month:'2-digit',day:'2-digit'}).formatToParts(x).map(p=>[p.type,p.value]));
const iso=x=>{const p=d(x);return `${p.year}-${p.month}-${p.day}`};
const today=iso(new Date()),yesterday=new Date(Date.parse(today+'T00:00:00Z')-86400000).toISOString().slice(0,10);
const arr=(v,f)=>Array.isArray(v)?v:(v?String(v).replace(/[{}]/g,'').split(',').map(x=>x.trim().replace(/^"|"$/g,'')):f);
return [{json:{...c,ad_account_id:String(c.ad_account_id||'').replace(/^act_/i,''),today,yesterday,report_date:today,conversion_action_types:arr(c.conversion_action_types,['lead','onsite_conversion.messaging_conversation_started_7d']),attribution_windows:arr(c.attribution_windows,['7d_click','1d_view'])}}];

const c=$('Preparar cliente').item.json,r=$json||{},payload=r.body??r,status=Number(r.statusCode??r.status??0);
const num=v=>Number.isFinite(Number(v))?Number(v):0, rows=Array.isArray(payload.data)?payload.data:[], err=r.error||payload.error||(!(status>=200&&status<300)?{message:`Meta ads HTTP ${status||'sem status'}`} :null);
const match=(v,ps)=>(ps||[]).some(p=>{p=String(p);return p.endsWith('*')?v.startsWith(p.slice(0,-1)):p.includes('%')?new RegExp('^'+p.replace(/[.*+?^${}()|[\]\\]/g,'\\$&').replace(/%/g,'.*')+'$').test(v):v===p});
const sum=(a,ps)=>Array.isArray(a)?a.reduce((s,x)=>s+(match(String(x.action_type||''),ps)?num(x.value):0),0):0;
const first=(a,ps)=>{if(!Array.isArray(a))return 0;for(const p of ps){const x=a.find(z=>match(String(z.action_type||''),[p]));if(x)return num(x.value)}return a[0]?num(a[0].value):0};
const metric=row=>{row=row||{};const spend=num(row.spend),conv=sum(row.actions,c.conversion_action_types),value=sum(row.action_values,['purchase','omni_purchase','offsite_conversion.fb_pixel_purchase','offsite_conversion.custom.%']);return {spend,reach:num(row.reach),impressions:num(row.impressions),frequency:num(row.frequency),clicks:num(row.clicks),ctr:num(row.ctr),cpc:num(row.cpc),cpm:num(row.cpm),conversions:conv,cost_per_result:conv?spend/conv:0,conversion_value:value,roas:first(row.purchase_roas,['omni_purchase','offsite_conversion.fb_pixel_purchase'])||(spend?value/spend:0)}};
const byDate=x=>rows.find(r=>r.date_start===x)||{},today=metric(byDate(c.today)),yesterday=metric(byDate(c.yesterday));
const variation=(a,b)=>b===0?(a===0?'0,0%':'novo/sem base'):`${((a-b)/Math.abs(b)*100)>0?'+':''}${((a-b)/Math.abs(b)*100).toLocaleString('pt-BR',{minimumFractionDigits:1,maximumFractionDigits:1})}%`;
const money=v=>new Intl.NumberFormat('pt-BR',{style:'currency',currency:String(c.currency||'BRL').trim()}).format(v),n=(v,d=0)=>v.toLocaleString('pt-BR',{minimumFractionDigits:d,maximumFractionDigits:d});
const enabled=new Set(Array.isArray(c.metrics)?c.metrics:['spend','reach','impressions','frequency','clicks','ctr','cpc','cpm','conversions','cost_per_result','roas']), lines=[],add=(k,label,val,d=0,suffix='')=>{if(enabled.has(k))lines.push(`${label}: ${n(val,d)}${suffix} (${variation(val,yesterday[k])})`)};
if(enabled.has('spend'))lines.push(`💰 Investimento: ${money(today.spend)} (${variation(today.spend,yesterday.spend)})`);add('reach','👥 Alcance',today.reach);add('impressions','👁️ Impressões',today.impressions);add('frequency','🔁 Frequência',today.frequency,2,'x');add('clicks','🖱️ Cliques',today.clicks);add('ctr','📈 CTR',today.ctr,2,'%');if(enabled.has('cpc'))lines.push(`💳 CPC: ${money(today.cpc)} (${variation(today.cpc,yesterday.cpc)})`);if(enabled.has('cpm'))lines.push(`📣 CPM: ${money(today.cpm)} (${variation(today.cpm,yesterday.cpm)})`);add('conversions','🎯 Resultados',today.conversions);if(enabled.has('cost_per_result'))lines.push(`💵 Custo por resultado: ${money(today.cost_per_result)} (${variation(today.cost_per_result,yesterday.cost_per_result)})`);add('roas','📊 ROAS',today.roas,2,'x');
const date=new Date(c.report_date+'T12:00:00Z').toLocaleDateString('pt-BR',{timeZone:'UTC'}),empty=today.spend===0&&today.impressions===0&&today.reach===0;
const message=empty?`Olá, ${c.client_name}! 👋

📊 Relatório diário de campanhas — ${date}

Hoje não identificamos veiculação ou consumo de orçamento nas campanhas monitoradas. Nossa equipe seguirá acompanhando.

R2R Marketing Digital`:`Olá, ${c.client_name}! 👋

📊 Relatório diário de campanhas — ${date}

${lines.join('\n')}

🔎 Comparativo em relação ao dia anterior.
ℹ️ Os dados do Meta ads podem receber atualizações posteriores.

R2R Marketing Digital`;
const channel=String(c.channel||'').toLowerCase(),valid=!err&&['whatsapp','email'].includes(channel)&&Boolean(c.destination);
return [{json:{...c,channel,data_valid:valid,api_error:err?(err.message||JSON.stringify(err)):(!valid?'Canal ou destino inválido':null),metrics_today:today,metrics_yesterday:yesterday,message,email_subject:`Relatório diário Meta ads — ${c.client_name} — ${date}`,delivery_status:empty?'no_activity':'sent'}}];
